    def test_partial_no_args_function(self):
        f = partial(no_args)
        assert f() == 42

    def test_partial_single_arg_function(self):
        f = partial(single, 99)
        assert f() == 99

    def test_partial_with_lambda(self):
        square = partial(lambda x, n: x ** n, n=2)
        assert square(4) == 16

    def test_partial_chained(self):
